  1	import React, { useEffect, useState } from 'react';
  2	
  3	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
  4	import { NumberInput, Skeleton, Text, TextVariants, Title } from '@patternfly/react-core';
  5	
  6	import { useDebounceCallback } from '../../../../../../utils/hooks/useDebounceCallback';
  7	import {
  8	  getLiveMigrationConfig,
  9	  MIGRATION_PER_CLUSTER,
 10	  MIGRATION_PER_NODE,
 11	  updateLiveMigrationConfig,
 12	} from '../utils/utils';
 13	
 14	const Limits = ({ hyperConverge }) => {
 15	  const { t } = useKubevirtTranslation();
 16	
 17	  const [migrationPerNode, setMigrationPerNode] = useState<number>();
 18	  const [migrationPerCluster, setMigrationPerCluster] = useState<number>();
 19	  const updateValuesCluster = useDebounceCallback(updateLiveMigrationConfig, 500);
 20	  const updateValuesNode = useDebounceCallback(updateLiveMigrationConfig, 500);
 21	
 22	  useEffect(() => {
 23	    if (hyperConverge) {
 24	      const liveMigrationConfig = getLiveMigrationConfig(hyperConverge);
 25	      migrationPerCluster ??
 26	        setMigrationPerCluster(Number(liveMigrationConfig?.parallelMigrationsPerCluster) || 0);
 27	      migrationPerCluster ??
 28	        setMigrationPerNode(Number(liveMigrationConfig?.parallelOutboundMigrationsPerNode) || 0);
 29	    }
 30	  }, [hyperConverge, migrationPerCluster, migrationPerNode]);
 31	
 32	  return (
 33	    <>
 34	      <Text component={TextVariants.small}>{t('Set live migration limits')}</Text>
 35	      <div className="live-migration-tab__number--container">
 36	        <div className="live-migration-tab__number--cluster">
 37	          <Title headingLevel="h6" size="md">
 38	            {t('Max. migrations per cluster')}
 39	          </Title>
 40	          {!isNaN(migrationPerCluster) ? (
 41	            <NumberInput
 42	              onChange={(event: React.ChangeEvent<HTMLInputElement>) => {
 43	                Number(event.target.value) >= 0 &&
 44	                  setMigrationPerCluster(() => {
 45	                    updateValuesCluster(
 46	                      hyperConverge,
 47	                      Number(event.target.value),
 48	                      MIGRATION_PER_CLUSTER,
 49	                    );
 50	                    return Number(event.target.value);
 51	                  });
 52	              }}
 53	              onMinus={() =>
 54	                setMigrationPerCluster((newMigrationPerCluster) => {
 55	                  updateValuesCluster(
 56	                    hyperConverge,
 57	                    newMigrationPerCluster - 1,
 58	                    MIGRATION_PER_CLUSTER,
 59	                  );
 60	                  return newMigrationPerCluster - 1;
 61	                })
 62	              }
 63	              onPlus={() =>
 64	                setMigrationPerCluster((newMigrationPerCluster) => {
 65	                  updateValuesCluster(
 66	                    hyperConverge,
 67	                    newMigrationPerCluster + 1,
 68	                    MIGRATION_PER_CLUSTER,
 69	                  );
 70	                  return newMigrationPerCluster + 1;
 71	                })
 72	              }
 73	              inputName={MIGRATION_PER_CLUSTER}
 74	              min={0}
 75	              value={migrationPerCluster}
 76	            />
 77	          ) : (
 78	            <Skeleton height={'33px'} width={'140px'} />
 79	          )}
 80	        </div>
 81	        <div>
 82	          <Title headingLevel="h6" size="md">
 83	            {t('Max. migrations per node')}
 84	          </Title>
 85	          {!isNaN(migrationPerNode) ? (
 86	            <NumberInput
 87	              onChange={(event: React.ChangeEvent<HTMLInputElement>) =>
 88	                Number(event.target.value) >= 0 &&
 89	                setMigrationPerNode(() => {
 90	                  updateValuesNode(hyperConverge, Number(event.target.value), MIGRATION_PER_NODE);
 91	                  return Number(event.target.value);
 92	                })
 93	              }
 94	              onMinus={() =>
 95	                setMigrationPerNode((newMigrationPerNode) => {
 96	                  updateValuesNode(hyperConverge, newMigrationPerNode - 1, MIGRATION_PER_NODE);
 97	                  return newMigrationPerNode - 1;
 98	                })
 99	              }
100	              onPlus={() =>
101	                setMigrationPerNode((newMigrationPerNode) => {
102	                  updateValuesNode(hyperConverge, newMigrationPerNode + 1, MIGRATION_PER_NODE);
103	                  return newMigrationPerNode + 1;
104	                })
105	              }
106	              inputName={MIGRATION_PER_NODE}
107	              min={0}
108	              value={migrationPerNode}
109	            />
110	          ) : (
111	            <Skeleton height={'33px'} width={'140px'} />
112	          )}
113	        </div>
114	      </div>
115	    </>
116	  );
117	};
118	
119	export default Limits;

